ALGORITHM FSPL_CALCULATION
INPUT: transmit_power_dBm, frequency_MHz, distance_km
OUTPUT: received_power_dBm

BEGIN
 // Convert frequency to wavelength in meters
 wavelength_m = 300 / frequency_MHz

 // Free Space Path Loss (FSPL) in dB
 // FSPL = 20 * log10(d) + 20 * log10(f) + 20 * log10(4π/c)
 // Simplified: FSPL = 20*log10(d) + 20*log10(f) + 32.44

 fspl_db = 20 * log10(distance_km * 1000) 
 + 20 * log10(frequency_MHz) 
 + 32.44

 // Received power
 received_power_dBm = transmit_power_dBm - fspl_db

 RETURN received_power_dBm
END

// Example: 1W (30 dBm) transmitter at 2.4 GHz, 100m distance
// wavelength = 300/2400 = 0.125m
// FSPL = 20*log10(100) + 20*log10(2400) + 32.44 = 40 + 67.6 + 32.44 = 140 dB
// Received = 30 - 140 = -110 dBm

ALGORITHM SHANNON_CAPACITY
INPUT: bandwidth_Hz, signal_power_W, noise_power_W
OUTPUT: capacity_bps, spectral_efficiency

BEGIN
 // Calculate SNR (Signal to Noise Ratio)
 snr = signal_power_W / noise_power_W
 snr_db = 10 * log10(snr)

 // Shannon's capacity theorem
 // C = B * log2(1 + SNR)
 capacity_bps = bandwidth_Hz * log2(1 + snr)

 // Spectral efficiency (bits/second/Hz)
 spectral_efficiency = log2(1 + snr)

 PRINT "SNR: ", snr_db, " dB"
 PRINT "Channel Capacity: ", capacity_bps, " bps"
 PRINT "Spectral Efficiency: ", spectral_efficiency, " bps/Hz"

 RETURN capacity_bps
END

// Example: 20 MHz bandwidth, SNR = 100 (20 dB)
// C = 20,000,000 * log2(101) ≈ 132 Mbps
